        print "5. Batch validate\n";
        print "6. Exit\n";
        print "Choose option: ";
        
        my $choice = <STDIN>;
        chomp $choice;
        
        if ($choice == 1) {
            print "\nAvailable patterns: ", join(", ", keys %config_patterns), "\n";
            print "Enter pattern name: ";
            my $pattern_name = <STDIN>;
            chomp $pattern_name;
            
            if (exists $config_patterns{$pattern_name}) {
                print "Enter string to validate: ";
                my $input = <STDIN>;
                chomp $input;
                
                if (validate_input($input, $config_patterns{$pattern_name})) {
                    print "✓ Valid\n";
                } else {
                    print "✗ Invalid\n";
                }
            } else {
                print "Pattern not found\n";
            }
            
        } elsif ($choice == 2) {
            print "Enter custom regex pattern: ";
            my $user_pattern = <STDIN>;
            chomp $user_pattern;
            
            print "Enter string to validate: ";
            my $input = <STDIN>;
            chomp $input;
            
            if (validate_with_eval($input, $user_pattern)) {
                print "✓ Valid\n";
            } else {
                print "✗ Invalid\n";
            }
            
        } elsif ($choice == 3) {
            print "Enter pattern name: ";
            my $name = <STDIN>;
            chomp $name;
            
            print "Enter regex pattern: ";
            my $pattern = <STDIN>;
            chomp $pattern;
            
            $config_patterns{$name} = $pattern;
            print "Pattern added successfully\n";
            
        } elsif ($choice == 4) {
            print "\nAvailable patterns:\n";
            foreach my $name (sort keys %config_patterns) {
                print "  $name: $config_patterns{$name}\n";
            }
            
        } elsif ($choice == 5) {
            print "Enter pattern name or custom pattern: ";
            my $pattern_input = <STDIN>;
            chomp $pattern_input;
            
            my $pattern = exists $config_patterns{$pattern_input} 
                ? $config_patterns{$pattern_input} 
                : $pattern_input;
            
            print "Enter strings to validate (one per line, empty line to finish):\n";
            my @inputs;
            while (my $line = <STDIN>) {
                chomp $line;
                last if $line eq '';
                push @inputs, $line;
            }
            
            print "\nResults:\n";
            foreach my $input (@inputs) {
