sub command_line_mode {
    my ($pattern, $input) = @_;
    
    if (exists $config_patterns{$pattern}) {
        $pattern = $config_patterns{$pattern};
    }
    
    if (validate_with_eval($input, $pattern)) {
        print "Valid\n";
        exit 0;
    } else {
        print "Invalid\n";
        exit 1;
    }
}

if (@ARGV >= 2) {
    command_line_mode($ARGV[0], $ARGV[1]);
} elsif (@ARGV == 1 && -e $ARGV[0]) {
    my %custom = load_custom_patterns($ARGV[0]);
    %config_patterns = (%config_patterns, %custom);
    print "Loaded " . scalar(keys %custom) . " custom patterns\n";
    interactive_mode();
} else {
    interactive_mode();
}